INSERT INTO preference.synthetic_persona_tag_preferences ( persona_id, tag_id, preference_type, preference_strength ) SELECT CAST(source.persona_id AS uuid), tag.id, source.preference_type, CAST(source.preference_strength AS numeric) FROM ( VALUES
( #{row.personaId}, #{row.tagCode}, #{row.preferenceType}, #{row.preferenceStrength} )
) AS source(persona_id, tag_code, preference_type, preference_strength) JOIN preference.preference_tags tag ON tag.code = source.tag_code AND tag.is_active = true
